import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";

const fmt = (d) => d ? new Date(d).toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"}) : "";
const statusCfg = {
  accepted: { bg:"rgba(74,222,128,0.08)", border:"rgba(74,222,128,0.25)", color:"#4ade80", icon:"✅" },
  rejected: { bg:"rgba(248,113,113,0.08)", border:"rgba(248,113,113,0.25)", color:"#f87171", icon:"❌" },
  pending:  { bg:"rgba(251,191,36,0.08)", border:"rgba(251,191,36,0.25)", color:"#fbbf24", icon:"⏳" },
};

export default function MyProposals() {
  const navigate = useNavigate();
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get("/proposals/my").then(r=>{setProposals(r.data||[]);setLoading(false);}).catch(()=>setLoading(false));
  }, []);

  const S = {
    page: { background:"#0f172a", minHeight:"100vh", padding:"32px", fontFamily:"'Segoe UI',sans-serif" },
    title: { fontSize:"24px", fontWeight:"700", color:"#f1f5f9", marginBottom:"4px" },
    sub: { fontSize:"13px", color:"#64748b", marginBottom:"28px" },
    card: (s) => {
      const c = statusCfg[s] || statusCfg.pending;
      return { background:"#1e293b", border:`1px solid #334155`, borderRadius:"14px", padding:"20px", marginBottom:"14px", borderLeft:`4px solid ${c.color}` };
    },
    row: { display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:"12px" },
    pTitle: { fontSize:"16px", fontWeight:"700", color:"#f1f5f9", marginBottom:"4px" },
    msg: { fontSize:"13px", color:"#94a3b8", lineHeight:1.5 },
    badge: (s) => {
      const c = statusCfg[s]||statusCfg.pending;
      return { display:"inline-flex", alignItems:"center", gap:"4px", padding:"4px 12px", borderRadius:"20px", fontSize:"11px", fontWeight:"700", background:c.bg, border:`1px solid ${c.border}`, color:c.color, textTransform:"capitalize" };
    },
    metaRow: { display:"flex", gap:"18px", fontSize:"12px", color:"#475569", marginTop:"12px", paddingTop:"12px", borderTop:"1px solid #334155" },
    bid: { color:"#4ade80", fontWeight:"700" },
  };

  if (loading) return <div style={{...S.page,display:"flex",alignItems:"center",justifyContent:"center"}}><span style={{color:"#2dd4bf"}}>Loading...</span></div>;

  return (
    <div style={S.page}>
      <h1 style={S.title}>My Proposals</h1>
      <p style={S.sub}>Track all proposals you have submitted</p>

      {proposals.length === 0 ? (
        <div style={{textAlign:"center",padding:"60px",color:"#475569"}}>
          <div style={{fontSize:"40px",marginBottom:"12px"}}>📄</div>
          <p>No proposals yet.</p>
          <button onClick={()=>navigate("/freelancer/find-projects")} style={{marginTop:"12px",padding:"9px 20px",borderRadius:"8px",border:"none",background:"linear-gradient(135deg,#0d9488,#0891b2)",color:"white",fontSize:"13px",fontWeight:"700",cursor:"pointer"}}>Find Projects →</button>
        </div>
      ) : proposals.map(p => (
        <div key={p.id} style={S.card(p.status)}>
          <div style={S.row}>
            <div>
              <p style={S.pTitle}>{p.project_title}</p>
              <p style={S.msg}>{p.message}</p>
            </div>
            <span style={S.badge(p.status)}>{(statusCfg[p.status]||statusCfg.pending).icon} {p.status||"pending"}</span>
          </div>
          <div style={S.metaRow}>
            <span>Your Bid: <span style={S.bid}>₹{p.bid}</span></span>
            {p.project_budget && <span>Budget: ₹{p.project_budget}</span>}
            {p.created_at && <span>📅 {fmt(p.created_at)}</span>}
            {p.project_deadline && <span>Due: {fmt(p.project_deadline)}</span>}
          </div>
        </div>
      ))}
    </div>
  );
}
